import React from 'react';

function UserInfo(props) {
  return (
    <div>
      <h1>Salam, {props.name}!</h1>
      <p>Yaş: {props.age}</p>
    </div>
  );
}

function App() {
  return <UserInfo name="Aysel" age={20} />;
}

console.log('Props ilə komponent yaradıldı');

import React from 'react';

function ItemList(props) {
  return (
    <ul>
      {props.items.map((item, index) => (
        <li key={index}>{item}</li>
      ))}
    </ul>
  );
}

function App() {
  const fruits = ['Alma', 'Armud', 'Gilas'];
  return <ItemList items={fruits} />;
}

console.log('Props ilə siyahı komponenti yaradıldı');

import React from 'react';

class UserInfo extends React.Component {
  render() {
    return (
      <div>
        <h1>Salam, {this.props.name}!</h1>
        <p>Yaş: {this.props.age}</p>
      </div>
    );
  }
}

function App() {
  return <UserInfo name="Aysel" age={20} />;
}

console.log('Class komponentdə props yaradıldı');

import React from 'react';

function Welcome(props) {
  return <h1>Salam, {props.name}!</h1>;
}

Welcome.defaultProps = {
  name: 'Qonaq'
};

function App() {
  return (
    <div>
      <Welcome />
      <Welcome name="Aysel" />
    </div>
  );
}

